                           / self.queries_total.load(Ordering::Relaxed).max(1) as f64,
            sweep_tasks_completed: self.sweep_tasks_completed.load(Ordering::Relaxed),
            delta_merges: self.delta_merges.load(Ordering::Relaxed),
