                    (Some(_), None) => panic!("FALSE POSITIVE: returned a dead fact"),
                    (None, None) => {} // both agree it's gone — correct
                }
            }
        });
    });

    Ok(AcceptanceReport {
        verdict: "SHIP",
        invariants_held: 4, // correctness, poison-resist, delete-filter, concurrency
    })
}

