        self.metrics.read_amp.store(self.engine.metrics.segments_read_last_query(), Ordering::Relaxed);
        self.metrics.write_amp.store(self.engine.metrics.nvme_bytes_written(), Ordering::Relaxed);
    }
}

pub struct TelemetryMetrics {
